import sys

def main():
    N = int(sys.stdin.readline())
    S = sys.stdin.readline().strip()

    count_t = 0
    count_a = 0
    t_reached_majority = False
    a_reached_majority = False
    winner = ''

    for char in S:
        if char == 'T':
            count_t += 1
            if not t_reached_majority and count_t > count_a:
                t_reached_majority = True
                winner = 'T'
        else:
            count_a += 1
            if not a_reached_majority and count_a > count_t:
                a_reached_majority = True
                winner = 'A'

    if count_t > count_a:
        print('T')
    elif count_a > count_t:
        print('A')
    else:
        print(winner)

if __name__ == "__main__":
    main()
